var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"휴우, 도와주셔서 고맙습니다. 태스크포스 여러분.","JPN":"ふう、タスクフォースカンパニーの皆様、助けていただきありがとうございます。","ENG":"Whew, thank you for your help, everyone from the TASKFORCE.","TWN":"呼，特遣勢力的各位，感謝大家的幫助。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"......여러분이 오셨다는 건, 경찰의 요청을 받고 오신 거겠죠?","JPN":"……皆様がここにいるということは、警察の要請を受けたということでしょうか？","ENG":"And you being here must mean that the police now know everything.","TWN":"……各位應該是聽了員警的要求才來幫忙的吧？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하하...... 여기 있으나, 구조 받으나, 철창 신세는 못 면하겠군요.","JPN":"ハハ……ここに居ても、救助してもらっても、監獄行きは免れないでしょうね。","ENG":"Hah hah... I guess behind bars is where I belong, one way or the other.","TWN":"哈哈……雖然在這裡得救了，但我應該無法避免入獄的命運吧。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이면세계에 떠도는 유실물을 현실세계로 빼돌린 죄가 얼마나 큰지는 저도 잘 알고 있으니까요.","JPN":"裏世界の遺失物を現実世界に持ち出した罪がどれほど大きいか、私もよく知っていますから。","ENG":"After all, transferring lost articles of the Counterside into our world is a sin that can't be forgiven.","TWN":"將異界中的遺物竊往現世，我也知道這是多嚴重的犯罪。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"......네? 경찰이 불러서 오신 게 아닙니까?","JPN":"……え？　警察の要請を受けていらしたのではないと？","ENG":"...Huh? It wasn't the police?","TWN":"……啊？你們不是員警叫來的？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그게 정말입니까?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"알리샤가...... 여러분께 저를 구해달라고 했다고요?","JPN":"アリシャが……皆様に救助の依頼をしたのですか？","ENG":"Alicia... She asked you to save me?","TWN":"是阿麗沙……請各位來救我的？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"우선, 알리샤는 제 비서가 아닙니다.","JPN":"まず、アリシャは私の秘書ではありません。","ENG":"First of all, Alicia isn't my secretary.","TWN":"首先，阿麗沙不是我的秘書。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"정확히는 제가 예전에 이면세계에서 찾아낸...... 아주 오래된 채굴용 로봇이죠.","JPN":"正確には私が以前裏世界で見つけた……とても古い採掘用ロボットです。","ENG":"To be precise, she's a very old mining robot that I discovered in the Counterside long ago.","TWN":"準確來說，她是我過去在異界找到的……歷史已久的採掘用機器人。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"기체의 손상이 너무 심해서 코어의 인공지능만 겨우 복원에 성공했는데,","JPN":"機体の損傷があまりにもひどく、コアの人工知能だけなんとか復元に成功したところ、","ENG":"The frames and chassis were too damaged, so I was only able to restore the A.I. equipped on the core.","TWN":"因為機體損傷過於嚴重，只復原了核心中的人工智慧。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"무턱대고 제게 이름을 정해달라기에 알리샤라는 이름을 붙여줬던 겁니다.","JPN":"とりあえず名前を付けてほしいと頼んできたので、アリシャと名付けてあげたのです。","ENG":"Alicia is the name I gave her when she persistently asked me to give her one.","TWN":"但她一直哀求叫我給她取名，所以我就給了她“阿麗沙”這個名字。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"사실 리퍼 인더스트리가 절 납치했던 이유도, 알리샤의 존재를 알아낸 놈들이 제게서 그녀의 명령권을 빼앗기 위해서였죠.","JPN":"リーファー・インダストリーが私を捕らえた理由も、アリシャの存在に気付いた連中が私から彼女への命令権を奪うためです。","ENG":"In fact, Reaper Industries kidnapped me because they wanted me to hand over the authority to command her.","TWN":"其實收割者工業之所以綁架我，也是因為知道了阿麗沙的存在，想從我這裡搶走她的命令權。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"그런데 제가 지키려 했던 인공지능에게 오히려 이런 식으로 도움을 받게 될 줄이야......","JPN":"私が守ろうとした人工知能に、逆に助けてもらうとは……","ENG":"I never thought I would be rescued by the A.I that I was trying to protect...","TWN":"但沒想到，我一直保護著的人工智慧，反而以這種方式救了我……"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 아직 이해가 안 되는 부분이 남아있습니다.","JPN":"しかしまだ理解できない部分があります。","ENG":"But there's something I don't understand.","TWN":"不過我還有些無法理解的事情。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"알리샤에겐 분명 인간을 해치지 않는다는 제 1원칙 명령코드를 심어뒀는데, 어떻게 여러분을 도와서 리퍼의 용병들과 싸웠던 걸까요?","JPN":"アリシャには人間に危害を加えないという第1原則命令コードが入力されているはずなのに、どうやって皆様と協力して、リーファー社の傭兵たちと戦ったのでしょう。","ENG":"Alicia was re-programmed to exercise the first law of robotics when I restored her. She can't hurt humans. How was it possible that she fought all the mercenaries alongside you?","TWN":"我明明為阿麗沙裝載了不能傷害人類的第一原則命令核心，她是怎麼幫助各位和傭兵戰鬥的呢？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"끄응...... 어쩌면 알리샤는 제가 통제할 수 있는 것처럼 흉내만 내고 있었을 지도 모르겠군요.","JPN":"ふむ……もしかしたらアリシャは今まで私にコントロールされているフリをしていただけかもしれませんね。","ENG":"*Moan* Maybe she was just pretending, so that I would think that I'm controlling her.","TWN":"呃...也許阿麗沙只是模仿出正被我控制的樣子吧。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"심지어 저를 구하기 위해 태스크포스를 고용할 정도로 능동적인 모습을 보이다니......","JPN":"しかも私を助けるためにタスクフォースを雇用するくらい、能動的な面を見せるとは……","ENG":"And then she reaches out to a TASKFORCE company to save me? That's active choice-making!","TWN":"甚至為了救我，能自主雇傭特遣勢力……"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"이면 세계의 로스트 태크놀로지란 건 정말 무섭군요.","JPN":"裏世界のロストテクノロジーは実に恐ろしいものですね。","ENG":"The lost technologies of the Counterside never cease to amaze me.","TWN":"異界的失落科技真是可怕啊。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"......하지만 무서운 것과는 별개로 전 과학자라서요.","JPN":"……しかし私は科学者ですから。","ENG":"Well, as much as I'm daunted, I'm a scientist.","TWN":"……不過無論可不可怕，畢竟我是科學家啊。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"알리샤를 관리국에 넘기기보단, 함께 지내면서 그녀를 좀 더 연구해보고 싶어요.","JPN":"アリシャを管理局に引き渡すより、一緒に過ごしながらもっと彼女を研究してみたいです。","ENG":"I'd rather stay with Alicia and study her than turn her over to the Administration.","TWN":"比起將阿麗沙交給管理局，我還是想與她待在一起，再多研究一下她。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"이 비밀을 지켜주신다면, 그 대가로 저희 회사의 제품을 지속적으로 제공하겠습니다.","JPN":"この秘密を守ってくださるなら、そのお礼として弊社の製品を継続的に提供させていただきます。","ENG":"If you could keep this between us, I promise you that I'll provide you with our products.","TWN":"若各位能保守這個秘密，作為回報，我們公司會持續為你們提供產品。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};